"use client";

import { useSearchParams, useRouter } from "next/navigation";
import Link from "next/link";

export default function ResultPage() {
  const searchParams = useSearchParams();
  const score = Number(searchParams.get("score") || 0);

  const getResultDetails = () => {
    if (score === 0)
      return {
        title: "Normal Stress Level",
        description:
          "Your stress levels appear to be within a healthy range. Keep maintaining good habits and emotional balance.",
        color: "text-green-600",
        bg: "bg-green-100",
        recommendations: [
          "Maintain your current healthy routines.",
          "Practice mindfulness or light meditation.",
          "Stay active and socially connected.",
        ],
      };

    if (score === 1)
      return {
        title: "Moderate Risk",
        description:
          "Your answers indicate a moderate amount of stress. It may be helpful to adjust routines or seek early support.",
        color: "text-yellow-600",
        bg: "bg-yellow-100",
        recommendations: [
          "Try guided breathing or meditation exercises.",
          "Improve sleep quality and daily rest.",
          "Talk to trusted friends or loved ones.",
        ],
      };

    return {
      title: "High Stress Level",
      description:
        "You may be experiencing high stress. Consider seeking professional support or guidance.",
      color: "text-red-600",
      bg: "bg-red-100",
      recommendations: [
        "Reach out to a mental health professional.",
        "Avoid stressful environments where possible.",
        "Engage in grounding or calming exercises.",
      ],
    };
  };

  const result = getResultDetails();

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-green-50 flex flex-col pt-28 px-6">
      <div className="max-w-2xl mx-auto text-center">
        {/* Icon */}
        <div
          className={`w-24 h-24 mx-auto rounded-full flex items-center justify-center shadow-md ${result.bg}`}
        >
          <span className="text-5xl">🧠</span>
        </div>

        {/* Title */}
        <h1 className="text-4xl font-bold mt-6 tracking-tight">
          Stress Assessment Result
        </h1>

        {/* Stress level text */}
        <h2 className={`text-2xl font-semibold mt-3 ${result.color}`}>
          {result.title}
        </h2>

        <p className="text-gray-600 mt-3 text-lg">{result.description}</p>

        {/* Recommendations */}
        <div className="mt-10 bg-white p-6 rounded-xl shadow-md border">
          <h3 className="text-xl font-semibold text-gray-800 mb-3">
            Recommended Next Steps
          </h3>

          <ul className="space-y-2 text-gray-700">
            {result.recommendations.map((tip, idx) => (
              <li key={idx} className="flex gap-2 items-start">
                <span className="text-blue-600 mt-[2px]">•</span>
                <span>{tip}</span>
              </li>
            ))}
          </ul>
        </div>

        {/* Links */}
        <div className="mt-8 flex justify-center gap-6">
          <Link
            href="/resources"
            className="px-5 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition"
          >
            View Resources
          </Link>

          <Link
            href="/"
            className="px-5 py-3 bg-lime-500 text-white rounded-lg hover:bg-lime-600 transition"
          >
            Back to Home
          </Link>
        </div>
      </div>
    </div>
  );
}
